import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import api from '../services/api';

const Login = ({ setIsAuthenticated }) => {
  const navigate = useNavigate();
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showError, setShowError] = useState(false);
  const [errorMessage, setErrorMessage] = useState('');
  const [loading, setLoading] = useState(false);
  const [rememberMe, setRememberMe] = useState(false);
  const [showPassword, setShowPassword] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setShowError(false);
    setErrorMessage('');
    setLoading(true);
    try {
      const response = await api.post('/auth/login', { email: email.trim(), password });
      const token = response.data.token;
      if (token) {
        if (rememberMe) {
          localStorage.setItem('nfxtoken', token);
        } else {
          sessionStorage.setItem('nfxtoken', token);
        }
        setIsAuthenticated(true);
        navigate('/', { replace: true }); // Navigate to DashboardHome
      } else {
        setShowError(true);
        setErrorMessage('No token received. Please try again.');
      }
    } catch (err) {
      setShowError(true);
      setErrorMessage(err.response?.data || 'Wrong credentials. Try again.');
      console.error('Login error:', err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="g-auth-bg">
      <div className="g-auth-card">
        <div className="g-auth-logo">
          <span className="g-dot g-blue"></span>
          <span className="g-dot g-red"></span>
          <span className="g-dot g-yellow"></span>
          <span className="g-dot g-green"></span>
          <h2 className="g-brand">NeuroFleetX</h2>
        </div>
        <h1 className="g-title">Sign in</h1>
        <p className="g-subtitle">Use your account</p>
        {showError && <div className="g-error">{errorMessage}</div>}
        <form onSubmit={handleSubmit} className="g-form">
          <div className="g-field">
            <input
              type="email"
              className="g-input"
              placeholder="Email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              autoComplete="username"
              required
            />
          </div>
          <div className="g-field relative">
            <input
              type={showPassword ? 'text' : 'password'}
              className="g-input pr-10"
              placeholder="Password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              autoComplete="current-password"
              required
            />
            <button
              type="button"
              className="g-toggle-password"
              onClick={() => setShowPassword(!showPassword)}
            >
              {showPassword ? 'Hide' : 'Show'}
            </button>
          </div>
          <div className="g-field flex items-center">
            <input
              type="checkbox"
              id="rememberMe"
              checked={rememberMe}
              onChange={(e) => setRememberMe(e.target.checked)}
              className="mr-2"
            />
            <label htmlFor="rememberMe" className="text-sm text-gray-600">Remember Me</label>
          </div>
          <div className="g-actions">
            <button type="submit" className="g-btn" disabled={loading}>
              {loading ? 'Signing in…' : 'Sign in'}
            </button>
          </div>
        </form>
        <div className="g-help">
          <Link to="/forgot-password">Forgot password?</Link>
          <span> • </span>
          <Link to="/signup">Sign up</Link>
        </div>
      </div>
    </div>
  );
};

export default Login;
